import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  Files, 
  Bell, 
  Sparkles, 
  X, 
  ChevronDown, 
  Boxes 
} from 'lucide-react';
import { ViewMode, ResourceItem, ModuleId, Tab } from './types';
import Sidebar from './components/Sidebar';
import Explorer from './components/Explorer';
import MainContent from './components/MainContent';
import AIAssistant from './components/AIAssistant';

const INITIAL_DATA: ResourceItem[] = [
  {
    id: 'f1', name: '0101 每日定时对账核销任务', type: 'workflow', description: '自动从ERP拉取流水并进行匹配...', version: 'v2.1', createdBy: 'liuqing', updatedAt: '2025-05-14 10:28:07', unreadCount: 1, tags: ['Finance', 'Batch']
  },
  {
    id: 'f2', name: '财务报表集成接口', type: 'connector', description: '财务报表集成数据流核心连接器', version: 'v1.0.2', createdBy: 'liuqing', updatedAt: '2025-05-14 17:28:09',
  },
  {
    id: 'f3', name: '对账核销模型-核心逻辑', type: 'model', description: '核心清算与对账业务模型', version: '3.0', createdBy: 'liuqing', updatedAt: '2025-05-23 10:38:41',
  }
];

const App: React.FC = () => {
  const [activeModule, setActiveModule] = useState<ModuleId>('pages');
  const [activeDrawerModule, setActiveDrawerModule] = useState<ModuleId | null>('recents');
  const [isAIShowing, setIsAIShowing] = useState(false);
  const [interfaceMode, setInterfaceMode] = useState<'dev' | 'user'>('dev');

  // Sidebar Resize Logic
  const [sidebarWidth, setSidebarWidth] = useState(64);
  const [isResizing, setIsResizing] = useState(false);
  const isExpanded = sidebarWidth > 120;

  // Multi-tab state
  const [tabs, setTabs] = useState<Tab[]>([
    { id: 'default-home', title: '页面展现', type: 'folder', moduleId: 'pages' }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('default-home');

  const startResizing = useCallback(() => {
    setIsResizing(true);
  }, []);

  const stopResizing = useCallback(() => {
    setIsResizing(false);
  }, []);

  const resize = useCallback((e: MouseEvent) => {
    if (isResizing) {
      const newWidth = Math.min(Math.max(64, e.clientX), 320);
      setSidebarWidth(newWidth);
    }
  }, [isResizing]);

  useEffect(() => {
    if (isResizing) {
      window.addEventListener('mousemove', resize);
      window.addEventListener('mouseup', stopResizing);
      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';
    } else {
      window.removeEventListener('mousemove', resize);
      window.removeEventListener('mouseup', stopResizing);
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    }
    return () => {
      window.removeEventListener('mousemove', resize);
      window.removeEventListener('mouseup', stopResizing);
    };
  }, [isResizing, resize, stopResizing]);

  const toggleSidebar = () => {
    setSidebarWidth(isExpanded ? 64 : 224);
  };

  const openTab = (item: ResourceItem | { id: string, name: string, type: any, moduleId?: ModuleId }) => {
    const existing = tabs.find(t => t.id === item.id);
    if (!existing) {
      const moduleId = 'moduleId' in item ? item.moduleId : undefined;
      setTabs([...tabs, { id: item.id, title: item.name, type: item.type, moduleId }]);
    }
    setActiveTabId(item.id);
  };

  const closeTab = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const newTabs = tabs.filter(t => t.id !== id);
    if (newTabs.length > 0) {
      if (activeTabId === id) {
        setActiveTabId(newTabs[newTabs.length - 1].id);
      }
      setTabs(newTabs);
    }
  };

  const moduleNames: Record<ModuleId, string> = {
    pages: '页面展现',
    logic: '流程逻辑',
    data: '数据模型',
    lakehouse: '数据湖仓',
    integration: '数据集成',
    services: '基础服务',
    v2: 'V2组件',
    finance: '场景-财务工具',
    recents: '最近打开与搜藏',
    elements: '元素管理'
  };

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-white selection:bg-blue-100 antialiased font-sans text-[13px]">
      <Sidebar 
        activeModule={activeModule} 
        onModuleChange={(id) => {
          setActiveModule(id);
          openTab({ id: `module-${id}`, name: moduleNames[id], type: 'folder', moduleId: id });
        }} 
        activeDrawerModule={activeDrawerModule}
        onDrawerChange={(id) => {
          setActiveDrawerModule(activeDrawerModule === id ? null : id);
        }}
        width={sidebarWidth}
        isExpanded={isExpanded}
        onToggleExpand={toggleSidebar}
        onResizeStart={startResizing}
        isResizing={isResizing}
        interfaceMode={interfaceMode}
        onModeToggle={(mode) => {
          setInterfaceMode(mode);
          setActiveModule(mode === 'dev' ? 'pages' : 'finance');
        }}
      />

      <div className="flex flex-col border-r border-slate-200 w-60 shrink-0 bg-white relative overflow-hidden">
        <div className="flex-1 flex flex-col min-h-0">
          <div className="h-14 flex items-center px-4 justify-between border-b border-slate-100 bg-white shrink-0">
            <span className="font-bold text-slate-800 tracking-tight flex items-center gap-2 text-[13px]">
              <div className="w-4 h-4 bg-blue-600 rounded flex items-center justify-center">
                <Boxes size={10} className="text-white" />
              </div>
              {interfaceMode === 'user' ? '财务对账核销目录' : moduleNames[activeModule]}
            </span>
          </div>
          <div className="flex-1 overflow-y-auto p-2">
            <Explorer 
              key={`${activeModule}-${interfaceMode}`} 
              activeModule={activeModule} 
              onSelectResource={(item) => openTab(item)}
              isUserMode={interfaceMode === 'user'} 
            />
          </div>
        </div>

        {interfaceMode === 'dev' && (
          <div className={`border-t border-slate-200 bg-slate-50 transition-all duration-300 ease-in-out flex flex-col ${
            activeDrawerModule ? 'h-[40%]' : 'h-0'
          }`}>
            <div className="h-9 flex items-center px-4 justify-between border-b border-slate-200 bg-white shrink-0">
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                {activeDrawerModule ? moduleNames[activeDrawerModule] : ''}
              </span>
              <button onClick={() => setActiveDrawerModule(null)} className="p-1 hover:bg-slate-100 rounded text-slate-400">
                <ChevronDown size={14} />
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-2">
              {activeDrawerModule && (
                <Explorer 
                  key={activeDrawerModule} 
                  activeModule={activeDrawerModule} 
                  onSelectResource={(item) => openTab(item)} 
                />
              )}
            </div>
          </div>
        )}
      </div>

      <div className="flex-1 flex flex-col min-w-0 bg-[#f8fafc]">
        <header className="h-14 flex items-center justify-between border-b border-slate-200 bg-white shrink-0 z-10">
          <div className="flex-1 flex h-full overflow-x-auto no-scrollbar items-end px-1 gap-0.5">
            {tabs.map((tab) => (
              <div 
                key={tab.id}
                onClick={() => setActiveTabId(tab.id)}
                className={`group h-[38px] flex items-center px-4 gap-2 text-[12px] font-medium cursor-pointer transition-all border-t-2 rounded-t-lg shrink-0 ${
                  activeTabId === tab.id 
                    ? 'bg-white border-blue-600 text-blue-700 shadow-[0_-2px_6px_rgba(0,0,0,0.02)]' 
                    : 'bg-transparent border-transparent text-slate-400 hover:text-slate-600'
                }`}
              >
                <Files size={12} className={activeTabId === tab.id ? 'text-blue-600' : 'text-slate-400'} />
                <span className="max-w-[120px] truncate">{tab.title}</span>
                <button 
                  onClick={(e) => closeTab(e, tab.id)}
                  className="p-0.5 rounded-full hover:bg-slate-100 opacity-0 group-hover:opacity-100 transition-opacity ml-1"
                >
                  <X size={10} />
                </button>
              </div>
            ))}
          </div>

          <div className="flex items-center gap-4 px-5 border-l border-slate-100 bg-white h-full shrink-0">
            <button onClick={() => setIsAIShowing(!isAIShowing)} className={`p-1.5 rounded-lg transition-colors ${isAIShowing ? 'bg-blue-50 text-blue-600' : 'text-slate-400 hover:bg-slate-100'}`}>
              <Sparkles size={18} />
            </button>
            <button className="p-1.5 text-slate-400 hover:bg-slate-100 rounded-lg relative">
              <Bell size={18} />
              <div className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border border-white"></div>
            </button>
            <div className="flex items-center gap-2 pl-2 border-l border-slate-100 ml-1">
              <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center text-white text-[12px] font-bold border-2 border-white shadow-sm">LQ</div>
            </div>
          </div>
        </header>

        <main className="flex-1 flex flex-row overflow-hidden relative">
          <div className="flex-1 overflow-hidden">
            <MainContent 
              data={INITIAL_DATA} 
              viewMode={ViewMode.EXPLORER} 
              activeTab={tabs.find(t => t.id === activeTabId)} 
            />
          </div>
          {isAIShowing && (
            <div className="w-80 border-l border-slate-200 bg-white shrink-0 animate-in slide-in-from-right duration-300 z-10 shadow-xl">
              <AIAssistant onClose={() => setIsAIShowing(false)} />
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { 
  Database, 
  Workflow, 
  Code2, 
  Layout, 
  Layers,
  Star,
  ChevronLeft,
  ChevronRight,
  Blocks,
  Network,
  Code,
  Smartphone,
  HardDrive,
  Settings2,
  Box,
  TrendingUp,
  MonitorCheck
} from 'lucide-react';
import { ModuleId } from '../types';

interface SidebarProps {
  activeModule: ModuleId;
  onModuleChange: (id: ModuleId) => void;
  activeDrawerModule: ModuleId | null;
  onDrawerChange: (id: ModuleId) => void;
  width: number;
  isExpanded: boolean;
  onToggleExpand: () => void;
  onResizeStart: () => void;
  isResizing: boolean;
  interfaceMode: 'dev' | 'user';
  onModeToggle: (mode: 'dev' | 'user') => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  activeModule, 
  onModuleChange, 
  activeDrawerModule,
  onDrawerChange,
  width,
  isExpanded, 
  onToggleExpand,
  onResizeStart,
  isResizing,
  interfaceMode,
  onModeToggle
}) => {

  const devCreationItems = [
    { id: 'pages', icon: <Layout size={18} />, label: '页面展现' },
    { id: 'logic', icon: <Code2 size={18} />, label: '流程逻辑' },
    { id: 'data', icon: <Database size={18} />, label: '数据模型' },
    { id: 'lakehouse', icon: <HardDrive size={18} />, label: '数据湖仓' },
    { id: 'integration', icon: <Network size={18} />, label: '数据集成' },
    { id: 'services', icon: <Settings2 size={18} />, label: '基础服务' },
    { id: 'v2', icon: <Box size={18} />, label: 'V2组件' },
    { id: 'finance', icon: <TrendingUp size={18} />, label: '场景-财务工具' },
  ] as const;

  const devFunctionalItems = [
    { id: 'recents', icon: <Star size={18} />, label: '最近打开与搜藏' },
    { id: 'elements', icon: <Blocks size={18} />, label: '元素管理' },
  ] as const;

  const userItems = [
    { id: 'finance', icon: <MonitorCheck size={18} />, label: '财务对账' },
    { id: 'recents', icon: <Star size={18} />, label: '我的收藏' },
  ] as const;

  const renderNavItems = (items: readonly { id: ModuleId, icon: React.ReactNode, label: string }[], isActive: (id: ModuleId) => boolean, onClick: (id: ModuleId) => void) => (
    <div className="px-2 flex flex-col gap-0.5 overflow-hidden">
      {items.map((item) => (
        <button
          key={item.id}
          onClick={() => onClick(item.id)}
          className={`flex items-center rounded-lg transition-colors group relative min-h-[36px] ${
            isActive(item.id) 
              ? 'bg-blue-50 text-blue-600 font-bold shadow-sm' 
              : 'text-slate-500 hover:bg-slate-100 hover:text-slate-700'
          } ${isExpanded ? 'px-3 py-1.5 w-full' : 'p-2 justify-center'}`}
        >
          <span className={`${isActive(item.id) ? 'scale-105' : 'scale-100'} transition-transform shrink-0`}>
            {item.icon}
          </span>
          {width > 120 && (
            <span 
              className="ml-3 text-[12px] whitespace-nowrap overflow-hidden transition-all duration-300"
              style={{ opacity: width > 160 ? 1 : 0, width: width > 160 ? 'auto' : 0 }}
            >
              {item.label}
            </span>
          )}
          {!isExpanded && (
            <div className="absolute left-full ml-3 px-2 py-1 bg-slate-800 text-white text-[10px] rounded opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity whitespace-nowrap z-50 shadow-lg">
              {item.label}
            </div>
          )}
        </button>
      ))}
    </div>
  );

  return (
    <aside 
      style={{ width: `${width}px` }}
      className={`relative h-full border-r border-slate-200 flex flex-col bg-white shrink-0 z-30 ${isResizing ? '' : 'transition-[width] duration-300 ease-in-out'}`}
    >
      {/* Resize Handle */}
      <div 
        onMouseDown={onResizeStart}
        className="absolute top-0 right-0 w-1 h-full cursor-col-resize hover:bg-blue-400/30 active:bg-blue-500/50 transition-colors z-50"
      />

      <div className="h-14 flex items-center px-3 shrink-0 overflow-hidden">
        <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-sm shrink-0">
          <Layers size={18} strokeWidth={2.5} />
        </div>
        {width > 120 && (
          <div className="ml-2 whitespace-nowrap transition-opacity duration-300" style={{ opacity: width > 160 ? 1 : 0 }}>
            <span className="font-black text-slate-800 tracking-tight block text-[13px]">NovaFlow</span>
            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest leading-none">Developer</span>
          </div>
        )}
      </div>

      <div className="flex-1 flex flex-col py-2 overflow-y-auto no-scrollbar gap-5">
        {interfaceMode === 'dev' ? (
          <>
            <div className="overflow-hidden">
              {width > 120 && <div className="px-5 mb-1 text-[9px] font-black text-slate-400 uppercase tracking-widest transition-opacity" style={{ opacity: width > 160 ? 1 : 0 }}>构建服务</div>}
              {renderNavItems(devCreationItems, (id) => activeModule === id, onModuleChange)}
            </div>
            <div className="mt-auto overflow-hidden">
              {width > 120 && <div className="px-5 mb-1 text-[9px] font-black text-slate-400 uppercase tracking-widest transition-opacity" style={{ opacity: width > 160 ? 1 : 0 }}>系统辅助</div>}
              {renderNavItems(devFunctionalItems, (id) => activeDrawerModule === id, onDrawerChange)}
            </div>
          </>
        ) : (
          <div className="overflow-hidden">
            {width > 120 && <div className="px-5 mb-1 text-[9px] font-black text-slate-400 uppercase tracking-widest transition-opacity" style={{ opacity: width > 160 ? 1 : 0 }}>应用中心</div>}
            {renderNavItems(userItems, (id) => activeModule === id, onModuleChange)}
          </div>
        )}
      </div>

      <div className="p-2 border-t border-slate-100 bg-slate-50/50 flex flex-col gap-2 shrink-0 overflow-hidden">
        <div className={`flex flex-col bg-white border border-slate-200 rounded-xl p-0.5 gap-0.5 ${!isExpanded && 'items-center'}`}>
          <button 
            onClick={() => onModeToggle('dev')}
            className={`flex items-center gap-2 p-1.5 rounded-lg transition-all w-full ${
              interfaceMode === 'dev' ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:bg-slate-50'
            } ${!isExpanded && 'justify-center'}`}
            title="开发态"
          >
            <Code size={16} />
            {width > 120 && <span className="text-[11px] font-black whitespace-nowrap" style={{ opacity: width > 160 ? 1 : 0 }}>开发态</span>}
          </button>
          <button 
            onClick={() => onModeToggle('user')}
            className={`flex items-center gap-2 p-1.5 rounded-lg transition-all w-full ${
              interfaceMode === 'user' ? 'bg-emerald-600 text-white shadow-sm' : 'text-slate-400 hover:bg-slate-50'
            } ${!isExpanded && 'justify-center'}`}
            title="运行态"
          >
            <Smartphone size={16} />
            {width > 120 && <span className="text-[11px] font-black whitespace-nowrap" style={{ opacity: width > 160 ? 1 : 0 }}>运行态</span>}
          </button>
        </div>

        <button onClick={onToggleExpand} className={`flex items-center gap-3 p-2 rounded-lg text-slate-400 hover:text-slate-600 transition-all ${!isExpanded && 'justify-center'}`}>
          {isExpanded ? <ChevronLeft size={18} /> : <ChevronRight size={18} />}
          {width > 120 && <span className="text-[12px] font-bold whitespace-nowrap" style={{ opacity: width > 160 ? 1 : 0 }}>收起侧栏</span>}
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;

import React from 'react';

export type ResourceType = 'folder' | 'page' | 'logic' | 'model' | 'stream' | 'connector' | 'component' | 'workflow' | 'db' | 'script' | 'chart';

export interface ResourceItem {
  id: string;
  name: string;
  type: ResourceType;
  description?: string;
  version: string;
  createdBy: string;
  updatedAt: string;
  children?: ResourceItem[];
  status?: 'active' | 'draft' | 'archived';
  unreadCount?: number;
  tags?: string[];
}

export interface Tab {
  id: string;
  title: string;
  type: ResourceType | 'module';
  moduleId?: ModuleId;
}

export enum ViewMode {
  EXPLORER = 'explorer',
  DESIGN = 'design',
  PREVIEW = 'preview'
}

// Added 'terminal' to ModuleId to fix type overlap error in MainContent.tsx and support terminal-specific logic
export type ModuleId = 
  | 'pages' 
  | 'logic' 
  | 'data' 
  | 'lakehouse' 
  | 'integration' 
  | 'services' 
  | 'v2' 
  | 'finance' 
  | 'recents' 
  | 'elements'
  | 'terminal';

export interface NavItem {
  id: ModuleId;
  label: string;
  icon: React.ReactNode;
}

