        width={sidebarWidth}
        isExpanded={isExpanded}
        onToggleExpand={toggleSidebar}
        onResizeStart={startResizing}
        isResizing={isResizing}
        interfaceMode={interfaceMode}
        onModeToggle={(mode) => {
          setInterfaceMode(mode);
          setActiveModule(mode === 'dev' ? 'pages' : 'finance');
