import React, { useState, useEffect, useCallback } from 'react';
import { 
  Files, 
  Bell, 
  Sparkles, 
  X, 
  ChevronDown, 
  Boxes,
  Layers,
  PanelLeftClose,
  PanelLeft
} from 'lucide-react';
