                      onSelectResource={(item) => openTab(item)} 
                    />
                  )}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Content Area - Naturally fills remaining space */}
        <main className="flex-1 flex flex-row overflow-hidden relative bg-[#f8fafc] z-10">
          <div className="flex-1 overflow-hidden">
