const Explorer: React.FC<ExplorerProps> = ({ 
  activeModule, 
  onSelectResource, 
  isUserMode, 
  activeTab,
  showContext = true,
  onCloseContext
}) => {
  const [expanded, setExpanded] = useState<Record<string, boolean>>({ 
    'dir_0101': true, 
    'dir_0301': true,
    'quick-recent': true,
    'quick-fav': false
  });
  const [showCode, setShowCode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const [contextHeight, setContextHeight] = useState(320);
  const [isResizing, setIsResizing] = useState(false);

  const startResizing = useCallback(() => setIsResizing(true), []);
  const stopResizing = useCallback(() => setIsResizing(false), []);

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (isResizing) {
      const newHeight = window.innerHeight - e.clientY;
      if (newHeight > 150 && newHeight < window.innerHeight - 200) {
        setContextHeight(newHeight);
      }
    }
  }, [isResizing]);

  useEffect(() => {
    if (isResizing) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', stopResizing);
    } else {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', stopResizing);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', stopResizing);
    };
  }, [isResizing, handleMouseMove, stopResizing]);

  const toggleExpand = (id: string) => setExpanded(prev => ({ ...prev, [id]: !prev[id] }));

  const filteredTree = useMemo(() => {
    if (!searchQuery) return TREE_DATA;
    const lowerQuery = searchQuery.toLowerCase();
    return TREE_DATA.map(dir => ({
      ...dir,
      children: dir.children?.filter(item => 
        item.name.toLowerCase().includes(lowerQuery) || item.code.toLowerCase().includes(lowerQuery)
      )
    })).filter(dir => dir.children && dir.children.length > 0);
  }, [searchQuery]);

  const mockRelations: ResourceItem[] = [
    { id: 'rel_1', name: '核心核销逻辑', code: 'RECON_LOGIC', type: 'logic', version: '1.0', createdBy: 'admin', updatedAt: '2025-05-14' },
