import React from 'react';
import { 
  ChevronLeft,
  ChevronRight,
  Blocks,
  Hammer,
  UserCircle,
  MonitorCheck,
  Compass,
  Link2,
  Layout,
  Database,
  Workflow,
  Zap,
  Layers
} from 'lucide-react';
import { ModuleId } from '../types';

interface SidebarProps {
  activeModule: ModuleId;
  onModuleChange: (id: string) => void;
  activeDrawerModule: ModuleId | null;
  onDrawerChange: (id: ModuleId) => void;
  width: number;
  isExpanded: boolean;
  onToggleExpand: () => void;
  onResizeStart: () => void;
  isResizing: boolean;
  interfaceMode: 'dev' | 'user';
  onModeToggle: (mode: 'dev' | 'user') => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  activeModule, 
  onModuleChange, 
  activeDrawerModule,
  onDrawerChange,
  width,
  isExpanded, 
  onToggleExpand,
  onResizeStart,
  isResizing,
  interfaceMode,
  onModeToggle
}) => {

  // 恢复之前版本按模块分类的图标
  const devItems = [
    { id: 'resources', icon: <Compass size={18} />, label: '全量资源' },
