                      <div className="hidden group-hover:flex items-center gap-1 pr-1 absolute right-0 bg-gradient-to-l from-slate-50 to-transparent pl-4">
                        <button className="p-1 hover:text-blue-600"><Edit2 size={12} /></button>
                        <button className="p-1 hover:text-red-500"><Trash2 size={12} /></button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Resizable Element Context Drawer */}
      <div 
        style={{ 
          height: showContext ? `${contextHeight}px` : '0px',
          opacity: showContext ? 1 : 0,
          pointerEvents: showContext ? 'auto' : 'none'
        }} 
        className="border-t border-slate-200 bg-slate-50/80 flex flex-col shrink-0 relative transition-all duration-300 ease-in-out overflow-hidden z-10"
      >
        <div 
          onMouseDown={() => setIsResizing(true)}
          className="absolute -top-1 left-0 w-full h-2 cursor-ns-resize hover:bg-blue-400/30 transition-colors z-20"
        />

        <div className="h-9 flex items-center px-3 justify-between border-b border-slate-200 bg-white">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <Compass size={12} className="text-blue-600" /> 元素上下文
          </span>
          <button onClick={onCloseContext} className="p-1 hover:bg-slate-100 rounded text-slate-400 transition-colors">
            <ChevronDown size={14} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-3 space-y-4 no-scrollbar">
          {activeTab ? (
            <div className="space-y-4">
              <div className="bg-white p-2.5 rounded-lg border border-slate-200 shadow-sm space-y-1.5">
                <div className="flex items-center gap-2">
                  <div className="p-1.5 bg-blue-100 text-blue-600 rounded">
                    {getIconForType(activeTab.type as ResourceType)}
                  </div>
                  <div className="flex flex-col">
                    <span className="text-[12px] font-black text-slate-800 leading-tight">{activeTab.title}</span>
                    <span className="text-[10px] font-mono text-slate-400">{activeTab.code || '--'}</span>
                  </div>
                </div>
              </div>

              <section className="space-y-1.5">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                  <ShieldCheck size={10} className="text-blue-600" /> 权限信息
                </h4>
                <div className="bg-white/50 border border-slate-100 rounded-lg p-2 space-y-1.5 text-[11px]">
                  <div className="flex justify-between items-center"><span className="text-slate-500">查看权限:</span><span className="font-bold text-slate-700">liuqing, admin</span></div>
                  <div className="flex justify-between items-center"><span className="text-slate-500">管理权限:</span><span className="text-blue-600 font-bold">财务管理员组</span></div>
                </div>
              </section>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-30 grayscale p-4">
              <Compass size={32} className="mb-2" />
              <p className="text-[10px] font-bold uppercase tracking-widest">未选择元素</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Explorer;

