              <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" size={13} />
              <input 
                type="text" 
                placeholder="搜索资源..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-white border border-slate-200 rounded py-1.5 pl-8 pr-3 text-[12px] outline-none focus:border-blue-500 transition-all shadow-sm" 
              />
            </div>

            {/* Action Group: Plus + More */}
            <div className="flex items-center gap-0.5">
              <button className="w-8 h-8 flex items-center justify-center bg-white border border-slate-200 rounded text-slate-400 hover:text-blue-600 hover:border-blue-300 transition-all shadow-sm">
                <Plus size={16} />
              </button>

              <div className="relative" ref={moreMenuRef}>
                <button 
                  onClick={() => setIsMoreMenuOpen(!isMoreMenuOpen)}
