          } ${isExpanded ? 'px-3 py-1.5 w-full' : 'p-2 justify-center'}`}
        >
          <span className={`${isActive(item.id) ? 'scale-105' : 'scale-100'} transition-transform shrink-0`}>
            {item.icon}
          </span>
          {width > 120 && (
            <span 
              className="ml-3 text-[12px] whitespace-nowrap overflow-hidden transition-all duration-300"
              style={{ opacity: width > 160 ? 1 : 0, width: width > 160 ? 'auto' : 0 }}
            >
              {item.label}
            </span>
          )}
          {!isExpanded && (
            <div className="absolute left-full ml-3 px-2 py-1 bg-slate-800 text-white text-[10px] rounded opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity whitespace-nowrap z-50 shadow-lg">
              {item.label}
            </div>
          )}
        </button>
      ))}
    </div>
  );

  return (
    <aside 
      style={{ width: `${width}px` }}
      className={`relative h-full border-r border-slate-200 flex flex-col bg-white shrink-0 z-10 ${isResizing ? '' : 'transition-[width] duration-300 ease-in-out'}`}
    >
      <div onMouseDown={onResizeStart} className="absolute top-0 right-0 w-1 h-full cursor-col-resize hover:bg-blue-400/30 z-50" />

      <div className="flex-1 flex flex-col py-2 overflow-y-auto no-scrollbar gap-5">
        {interfaceMode === 'dev' ? (
          <>
            <div className="overflow-hidden">
              {width > 120 && <div className="px-5 mb-1 text-[9px] font-black text-slate-400 uppercase tracking-widest transition-opacity" style={{ opacity: width > 160 ? 1 : 0 }}>工作空间</div>}
              {renderNavItems(devItems, (id) => activeModule === id, onModuleChange)}
            </div>

            <div className="mt-auto overflow-hidden">
              {width > 120 && <div className="px-5 mb-1 text-[9px] font-black text-slate-400 uppercase tracking-widest transition-opacity" style={{ opacity: width > 160 ? 1 : 0 }}>系统辅助</div>}
              {renderNavItems(bottomTools, 
                (id) => (id === 'context' ? activeDrawerModule === 'context' : false), 
                (id) => {
                  if (id === 'elements') onModuleChange('elements');
                  else onDrawerChange(id as ModuleId);
                }
              )}
            </div>
          </>
        ) : (
          <div className="overflow-hidden">
            {width > 120 && <div className="px-5 mb-1 text-[9px] font-black text-slate-400 uppercase tracking-widest transition-opacity" style={{ opacity: width > 160 ? 1 : 0 }}>应用中心</div>}
            {renderNavItems(userItems, (id) => activeModule === id, onModuleChange)}
          </div>
        )}
      </div>

      <div className="p-2 border-t border-slate-100 bg-slate-50/50 flex flex-col gap-2 shrink-0">
        <div className={`flex flex-col bg-white border border-slate-200 rounded-xl p-0.5 gap-0.5 ${!isExpanded && 'items-center'}`}>
          <button onClick={() => onModeToggle('dev')} className={`flex items-center gap-2 p-1.5 rounded-lg transition-all w-full ${interfaceMode === 'dev' ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:bg-slate-50'}`}>
            <Hammer size={16} />
            {width > 120 && <span className="text-[11px] font-black" style={{ opacity: width > 160 ? 1 : 0 }}>设置管理</span>}
          </button>
          <button onClick={() => onModeToggle('user')} className={`flex items-center gap-2 p-1.5 rounded-lg transition-all w-full ${interfaceMode === 'user' ? 'bg-emerald-600 text-white shadow-sm' : 'text-slate-400 hover:bg-slate-50'}`}>
            <UserCircle size={16} />
            {width > 120 && <span className="text-[11px] font-black" style={{ opacity: width > 160 ? 1 : 0 }}>用户菜单</span>}
          </button>
        </div>
        <button onClick={onToggleExpand} className="flex items-center gap-3 p-2 rounded-lg text-slate-400 hover:text-slate-600 transition-all">
          {isExpanded ? <ChevronLeft size={18} /> : <ChevronRight size={18} />}
          {width > 120 && <span className="text-[12px] font-bold" style={{ opacity: width > 160 ? 1 : 0 }}>收起侧栏</span>}
        </button>
      </div>
    </aside>
  );
};

