const Explorer: React.FC<ExplorerProps> = ({ 
  activeModule, 
  onSelectResource, 
  isUserMode, 
  activeTab,
  showContext = true,
  onCloseContext
}) => {
  const [selectedModule, setSelectedModule] = useState('all');
  const [isModuleMenuOpen, setIsModuleMenuOpen] = useState(false);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [resourceViewMode, setResourceViewMode] = useState<'all' | 'recent' | 'fav'>('all');
  const [expanded, setExpanded] = useState<Record<string, boolean>>({ 'root_ux': true, 'root_model': true });
  const [searchQuery, setSearchQuery] = useState('');
  const [contextHeight, setContextHeight] = useState(320);

  const moduleMenuRef = useRef<HTMLDivElement>(null);
  const moreMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (moduleMenuRef.current && !moduleMenuRef.current.contains(event.target as Node)) setIsModuleMenuOpen(false);
      if (moreMenuRef.current && !moreMenuRef.current.contains(event.target as Node)) setIsMoreMenuOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const currentTree = useMemo(() => {
    if (activeModule === 'console') return CONSOLE_ITEMS;
    const data = resourceViewMode === 'all' ? (MODULE_DATA['all'] || []) : (resourceViewMode === 'recent' ? RECENT_ITEMS : FAVORITE_ITEMS);
    if (!searchQuery) return data;
    const lowerQuery = searchQuery.toLowerCase();
    return data.map(dir => dir.children ? ({
      ...dir,
      children: dir.children.filter(item => item.name.toLowerCase().includes(lowerQuery))
    }) : dir).filter(item => item.name.toLowerCase().includes(lowerQuery) || (item.children && item.children.length > 0));
  }, [activeModule, resourceViewMode, searchQuery]);

  const currentModule = useMemo(() => MODULE_OPTIONS.find(o => o.id === selectedModule) || MODULE_OPTIONS[0], [selectedModule]);

  return (
    <div className="flex flex-col h-full bg-white select-none relative">
      {/* Explorer Header */}
      <div className="h-14 flex items-center px-4 justify-between border-b border-slate-100 bg-white shrink-0">
        <div className="flex items-center gap-2">
          <span className="font-black text-slate-800 tracking-tight text-[13px] uppercase">
            {activeModule === 'console' ? '运维监控' : '资源管理'}
          </span>
          {activeModule === 'resources' && (
            <div className="flex bg-slate-100 p-0.5 rounded-lg ml-2">
              <button onClick={() => setResourceViewMode('all')} className={`p-1 rounded-md transition-all ${resourceViewMode === 'all' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}><Compass size={12} /></button>
              <button onClick={() => setResourceViewMode('recent')} className={`p-1 rounded-md transition-all ${resourceViewMode === 'recent' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}><History size={12} /></button>
              <button onClick={() => setResourceViewMode('fav')} className={`p-1 rounded-md transition-all ${resourceViewMode === 'fav' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}><Star size={12} /></button>
            </div>
          )}
        </div>
        <div className="flex items-center gap-1">
          <button className="p-1.5 text-slate-400 hover:bg-slate-50 rounded"><X size={14} /></button>
        </div>
      </div>

      <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
        {/* Toolbar - Only for Resources mode */}
        {activeModule === 'resources' && (
          <div className="p-2 space-y-2">
            <div className="relative">
              <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" size={13} />
              <input 
                type="text" placeholder="搜索资源..." value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded py-1.5 pl-8 pr-3 text-[12px] outline-none focus:border-blue-500 transition-all" 
              />
            </div>
            {resourceViewMode === 'all' && (
              <div className="flex items-center justify-between gap-1.5">
                <div className="relative flex-1" ref={moduleMenuRef}>
                  <button onClick={() => setIsModuleMenuOpen(!isModuleMenuOpen)} className="w-full flex items-center gap-2 px-2 py-1.5 rounded border border-slate-200 bg-white hover:border-blue-400 transition-all text-slate-700 shadow-sm">
                    <span className="text-blue-600">{currentModule.icon}</span>
                    <span className="text-[12px] font-medium flex-1 text-left">{currentModule.label}</span>
                    <ChevronDown size={12} className="text-slate-400" />
                  </button>
                  {isModuleMenuOpen && (
                    <div className="absolute left-0 top-full mt-1 w-48 bg-white border border-slate-100 rounded-lg shadow-xl z-50 py-1">
                      {MODULE_OPTIONS.map(opt => (
                        <button key={opt.id} onClick={() => { setSelectedModule(opt.id); setIsModuleMenuOpen(false); }} className="w-full flex items-center gap-2.5 px-3 py-2 text-[12px] hover:bg-slate-50 text-slate-600">
                          {opt.icon} {opt.label}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
                <div className="flex items-center gap-1">
                  <button className="w-8 h-8 flex items-center justify-center bg-white border border-slate-200 rounded text-slate-400 hover:text-blue-600 shadow-sm"><Plus size={16} /></button>
                  <div className="relative" ref={moreMenuRef}>
                    <button onClick={() => setIsMoreMenuOpen(!isMoreMenuOpen)} className="w-8 h-8 flex items-center justify-center rounded border border-slate-200 bg-white text-slate-400 shadow-sm"><MoreVertical size={16} /></button>
                    {isMoreMenuOpen && (
                      <div className="absolute right-0 top-full mt-1 w-40 bg-white border border-slate-100 rounded-lg shadow-xl z-50 py-1 text-[12px]">
                        <button className="w-full flex items-center gap-2.5 px-3 py-2 hover:bg-slate-50 text-slate-600"><Locate size={14} /> 定位当前元素</button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto px-1 no-scrollbar pb-10">
          {activeModule === 'resources' ? (
            currentTree.map(dir => (
              <div key={dir.id} className="mb-0.5">
                <div onClick={() => toggleExpand(dir.id)} className="flex items-center gap-2 p-1.5 hover:bg-slate-100/60 rounded cursor-pointer group">
                  <div className="w-4 h-4 flex items-center justify-center shrink-0">
                    {expanded[dir.id] ? <ChevronDown size={12} className="text-slate-400" /> : <ChevronRight size={12} className="text-slate-400" />}
                  </div>
                  {getIconForType(dir.type)}
                  <span className="text-[12px] font-medium text-slate-600 truncate">{dir.name}</span>
                </div>
                {expanded[dir.id] && dir.children && (
                  <div className="ml-5 border-l border-slate-100 mt-0.5">
                    {dir.children.map(item => (
                      <div key={item.id} onClick={() => onSelectResource(item)} className="flex items-center gap-2 p-1.5 pl-4 hover:bg-blue-50/50 rounded cursor-pointer group relative">
                        {getIconForType(item.type)}
                        <span className={`text-[12px] truncate flex-1 ${activeTab?.id === item.id ? 'text-blue-600 font-bold' : 'text-slate-500'}`}>{item.name}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ))
          ) : (
            /* Component Consoles - Card List Style */
            <div className="p-3 space-y-3">
              {CONSOLE_ITEMS.map(item => (
                <div 
                  key={item.id} 
                  onClick={() => onSelectResource(item)}
                  className={`group p-3 rounded-xl border transition-all cursor-pointer relative overflow-hidden ${
                    activeTab?.id === item.id ? 'bg-blue-50 border-blue-200 shadow-sm' : 'bg-white border-slate-100 hover:border-blue-200 hover:shadow-sm'
                  }`}
                >
                  <div className="flex items-start gap-3">
                    <div className={`p-2 rounded-lg ${activeTab?.id === item.id ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500 group-hover:bg-blue-50 group-hover:text-blue-600'}`}>
                      {item.code === 'PROC_MONITOR' ? <Activity size={18} /> : 
                       item.code === 'MODEL_HUB' ? <Database size={18} /> : 
                       item.code === 'SCHEDULER' ? <Clock size={18} /> : 
                       item.code === 'TERM_CENTER' ? <Terminal size={18} /> : <Zap size={18} />}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-0.5">
                        <span className={`text-[12px] font-bold truncate ${activeTab?.id === item.id ? 'text-blue-700' : 'text-slate-700'}`}>{item.name}</span>
                        {item.status === 'healthy' && <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>}
                        {item.status === 'warning' && <div className="w-1.5 h-1.5 rounded-full bg-amber-500"></div>}
                      </div>
                      <p className="text-[10px] text-slate-400 line-clamp-1">{item.description}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Context Drawer */}
      <div 
        style={{ height: showContext ? `${contextHeight}px` : '0px', opacity: showContext ? 1 : 0 }} 
        className="border-t border-slate-200 bg-slate-50/80 flex flex-col shrink-0 relative transition-all duration-300 ease-in-out overflow-hidden z-10"
      >
        <div className="h-9 flex items-center px-3 justify-between border-b border-slate-200 bg-white">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Compass size={12} className="text-blue-600" /> 元素上下文</span>
          <button onClick={onCloseContext} className="p-1 hover:bg-slate-100 rounded text-slate-400"><ChevronDown size={14} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-3 no-scrollbar text-[11px]">
          {activeTab ? (
            <div className="space-y-4">
               <div className="bg-white p-2.5 rounded-lg border border-slate-200 shadow-sm space-y-1">
                <div className="font-bold text-slate-800">{activeTab.title}</div>
                <div className="text-slate-400 font-mono text-[10px]">{activeTab.code}</div>
              </div>
              <section className="space-y-1.5">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">权限信息</h4>
                <div className="bg-white/50 border border-slate-100 rounded-lg p-2 space-y-1">
                  <div className="flex justify-between"><span className="text-slate-500">查看权限:</span><span>liuqing, admin</span></div>
                  <div className="flex justify-between"><span className="text-slate-500">管理权限:</span><span className="text-blue-600 font-bold">财务管理员组</span></div>
                </div>
              </section>
            </div>
          ) : <div className="h-full flex flex-col items-center justify-center opacity-30 grayscale"><Compass size={32} /></div>}
        </div>
      </div>
    </div>
  );
};

